export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  return inputs.subscriptions && inputs.subscriptions.length > 3;
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;

  return {
    average,
  };
};

export const code = async (inputs) => {
  const rawItems = Array.isArray(inputs.items) ? inputs.items : [];

  const ids = rawItems
    .map((item) => {
      if (!item) return null;

      if (typeof item === "string") {
        try {
          return JSON.parse(item)?.id || null;
        } catch {
          return null;
        }
      }

      if (typeof item === "object") {
        return item.id || null;
      }

      return null;
    })
    .filter(Boolean);

  return ids.map((id) => `"${id}"`).join(", ");
};

export const code = async (inputs) => {
  const costs = Array.isArray(inputs.costs) ? inputs.costs : [];
  const items = Array.isArray(inputs.items) ? inputs.items : [];

  const normalizeId = (value) => String(value || "").toLowerCase();

  const regionByResourceId = {};

  for (const rawItem of items) {
    if (!rawItem) continue;

    let item = rawItem;

    if (typeof rawItem === "string") {
      try {
        item = JSON.parse(rawItem);
      } catch {
        continue;
      }
    }

    if (!item || typeof item !== "object" || !item.id) continue;

    regionByResourceId[normalizeId(item.id)] =
      item.region ||
      item.location ||
      item.properties?.geoRegion ||
      null;
  }

  const grouped = {};

  for (const [cost, date, resourceId, currency] of costs) {
    const normalizedResourceId = normalizeId(resourceId);

    if (!grouped[normalizedResourceId]) {
      grouped[normalizedResourceId] = {
        resourceId,
        currency,
        region: regionByResourceId[normalizedResourceId] || null,
        datesWithCosts: []
      };
    }

    grouped[normalizedResourceId].datesWithCosts.push([cost, date]);
  }

  return Object.values(grouped);
};

export const code = async (inputs) => {
  const items = inputs.pricingItems || [];

  const today = new Date();
  const dateKey = Number(
    `${today.getUTCFullYear()}${String(today.getUTCMonth() + 1).padStart(2, "0")}${String(today.getUTCDate()).padStart(2, "0")}`
  );

  return items
    .map(item => {
      const parsedItem = typeof item === "string" ? JSON.parse(item) : item;

      return {
        region: parsedItem.location,
        resourceId: parsedItem.resourceId,
        currency: parsedItem.currency || "USD",
        datesWithCosts: [
          [
            parsedItem.dailyPricing || 0,
            dateKey
          ]
        ]
      };
    })
    .filter(item => item.resourceId);
};

export const code = async (inputs) => {
  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/\s+/g, "")
      .trim();

  const parseItem = (item) => {
    if (typeof item !== "string") return item;

    try {
      return JSON.parse(item);
    } catch {
      return null;
    }
  };

  const items = Array.isArray(inputs?.items)
    ? inputs.items
    : inputs?.items
      ? [inputs.items]
      : [];

  const region =
    inputs?.region?.serverValue ??
    inputs?.region?.value ??
    inputs?.region;

  const normalizedRegion = normalize(region);

  return items
    .map(parseItem)
    .filter(Boolean)
    .filter((item) => normalize(item?.location) === normalizedRegion);
};

export const code = async (inputs) => {
  const plans = Array.isArray(inputs.servicePlans) ? inputs.servicePlans : [];

  const counts = plans.reduce((acc, id) => {
    if (typeof id !== "string" || !id.trim()) return acc;
    const key = id.trim();
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});

  return Object.entries(counts).map(([appServicePlanId, unusedApps]) => ({
    appServicePlanId,
    unusedApps,
  }));
};

export const code = async (inputs) => {
  const normalizeItems = (value) => {
    if (Array.isArray(value)) return value;

    if (typeof value === "string") {
      try {
        const parsed = JSON.parse(value);
        return Array.isArray(parsed) ? parsed : [parsed];
      } catch {
        return [];
      }
    }

    if (value && typeof value === "object") {
      if (Array.isArray(value.data)) return value.data;
      if (Array.isArray(value.value)) return value.value;
      return [value];
    }

    return [];
  };

  const parseItem = (item) => {
    if (typeof item !== "string") return item;

    try {
      return JSON.parse(item);
    } catch {
      return null;
    }
  };

  const normalizeId = (value) =>
    String(value || "")
      .trim()
      .toLowerCase();

  const items = normalizeItems(inputs?.items);
  const appServicePlanId = normalizeId(inputs?.appServicePlanId);

  const webAppCount = items.reduce((count, item) => {
    const parsedItem = parseItem(item);

    const serverFarmId = normalizeId(
      parsedItem?.properties?.serverFarmId || parsedItem?.serverFarmId
    );

    return serverFarmId === appServicePlanId ? count + 1 : count;
  }, 0);

  return {
    id: inputs?.appServicePlanId || null,
    webAppCount,
  };
};

export const code = async (inputs) => {
  const normalizeItem = (item) => {
    if (typeof item === "string") {
      try {
        return JSON.parse(item);
      } catch {
        return null;
      }
    }

    return item && typeof item === "object" ? item : null;
  };

  const items = Array.isArray(inputs?.items)
    ? inputs.items.map(normalizeItem).filter(Boolean)
    : [normalizeItem(inputs?.items)].filter(Boolean);

  const appServicePlanId = String(inputs?.appServicePlanId || "").toLowerCase();

  return (
    items.find(
      (item) => String(item?.id || "").toLowerCase() === appServicePlanId
    ) || null
  );
};

