  };
};

export const code = async (inputs) => {
  const { appServicePlan, priceList } = inputs;

  const normalizeObject = (value) => {
    if (typeof value === "string") {
      try {
        return JSON.parse(value);
      } catch {
        return null;
      }
    }

    return value && typeof value === "object" ? value : null;
  };

  const plan = normalizeObject(appServicePlan);

  const items = Array.isArray(priceList)
    ? priceList.map(normalizeObject).filter(Boolean)
    : Array.isArray(priceList?.Items)
      ? priceList.Items.map(normalizeObject).filter(Boolean)
      : [];

  const resourceId =
    plan?.id ||
    plan?.resourceMetadata?.resourceId ||
    null;

  const location =
    plan?.location ||
    plan?.resourceMetadata?.location ||
    null;

  const sku = plan?.sku || {};
  const skuName = sku.name || sku.size || null;

  const isLinux =
    String(plan?.kind || "").toLowerCase().includes("linux") ||
    plan?.reserved === true;

  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/[_-]/g, "")
      .replace(/\s+/g, "")
      .trim();

  const normalizeSku = (value) =>
    normalize(value)
      .replace("v", "")
      .replace("app", "");

  const expectedSku = normalizeSku(skuName);

  if (!skuName) {
    return {
      resourceId,
      location,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const priceItem = items.find((p) => {
    if (p.type !== "Consumption") return false;
    if (p.serviceName !== "Azure App Service") return false;
    if (p.unitOfMeasure !== "1 Hour") return false;

    const priceSku = normalizeSku(p.skuName);
    const meterName = normalizeSku(p.meterName);
    const productName = String(p.productName || "").toLowerCase();

    if (priceSku !== expectedSku && !meterName.includes(expectedSku)) {
      return false;
    }

    if (isLinux && !productName.includes("linux")) {
      return false;
    }

    if (!isLinux && productName.includes("linux")) {
      return false;
    }

    if (
      productName.includes("ssl") ||
      productName.includes("domain") ||
      productName.includes("stamp") ||
      productName.includes("isolated") ||
      p.skuName === "ASIP" ||
      p.skuName === "Front End"
    ) {
      return false;
    }

    return true;
  });

  if (!priceItem || typeof priceItem.retailPrice !== "number") {
    return {
      resourceId,
      location,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const workerCount = Number(
    plan?.sku?.capacity ||
    plan?.properties?.numberOfWorkers ||
    plan?.numberOfWorkers ||
    1
  );

  return {
    resourceId,
    location,
    dailyPricing: priceItem.retailPrice * 24 * workerCount,
    currency: priceItem.currencyCode || "USD"
  };
};

export const code = async (inputs) => {
  const metrics = Array.isArray(inputs?.metrics?.value)
    ? inputs.metrics.value
    : Array.isArray(inputs?.metrics)
      ? inputs.metrics
      : [];

  const sumMetricTotal = (metricName) => {
    const metric = metrics.find(
      (m) => String(m?.name?.value || "").toLowerCase() === metricName.toLowerCase()
    );

    if (!metric || !Array.isArray(metric?.timeseries)) return 0;

    return metric.timeseries.reduce((sum, series) => {
      if (!Array.isArray(series?.data)) return sum;

      return sum + series.data.reduce((innerSum, point) => {
        const value =
          typeof point?.total === "number"
            ? point.total
            : Number(point?.total);

        return innerSum + (Number.isFinite(value) ? value : 0);
      }, 0);
    }, 0);
  };

  return {
    Requests: sumMetricTotal("Requests"),
    CpuTime: sumMetricTotal("CpuTime")
  };
};
